class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n))
        self.size = [1] * n

    def find(self, i):
        if self.parent[i] == i:
            return i
        self.parent[i] = self.find(self.parent[i])
        return self.parent[i]

    def union(self, i, j):
        root_i = self.find(i)
        root_j = self.find(j)

        if root_i != root_j:
            if self.size[root_i] < self.size[root_j]:
                root_i, root_j = root_j, root_i

            self.parent[root_j] = root_i
            self.size[root_i] += self.size[root_j]
            return True
        return False

def minimizeMalwareSpread(graph, initial):
    n = len(graph)
    uf = UnionFind(n)

    for i in range(n):
        for j in range(i + 1, n):
            if graph[i][j] == 1:
                uf.union(i, j)

    initial.sort()

    infected_count_per_component = {} 
    for node in initial:
        root = uf.find(node)
        infected_count_per_component[root] = infected_count_per_component.get(root, 0) + 1

    max_saved_nodes = 0
    node_to_remove = initial[0]

    for node in initial:
        root = uf.find(node)

        if infected_count_per_component[root] == 1:
            saved_nodes = uf.size[root]

            if saved_nodes > max_saved_nodes:
                max_saved_nodes = saved_nodes
                node_to_remove = node
            # If saved_nodes == max_saved_nodes, we stick with the smaller index node,
            # which is already captured by sorting `initial` and updating only on `>`
            # and `node_to_remove = initial[0]` as a default.

    return node_to_remove
